VALUES
  ('fire-eq-tech-moex-02680', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「耐燃電纜認可基準」規定，下列敘述何者有誤？', '["被覆之顏色，圓型者為黑色，平型者為灰色", "3.3 kV及 6.6 kV級電纜須施加一層0.05 mm以上厚度之銅帶作為遮蔽層，銅帶間至少須相互重疊帶寬 之10%", "高難燃無鹵性試驗之多條電纜垂直燃燒試驗合格判定基準為燃燒碳化長度小於1800 mm者（即未達到 梯架頂端）為合格", "聚氯乙烯被覆體耐油性試驗之油溫及浸泡時間為70℃±2℃及4小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02681', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「可燃性高壓氣體儲存場所防護牆設置基準」有關公共危險物品及可燃性高壓氣體設置標準暨安全管 理辦法第70條第8款所定防護牆之設置規定敘述，下列何者有誤？', '["鋼筋混凝土製者，其構造為厚度應在90 mm以上，高度應在2000 mm以上，鋼筋直徑應在9 mm以上， 配筋之縱橫間隔應在200 mm以下，角隅之鋼筋確實綁紮", "混凝土空心磚製者，其構造為厚度應在120 mm以上，高度應在2000 mm以上，鋼筋直徑應在9 mm以 上，配筋之縱橫間隔應在300 mm以下，角隅之鋼筋確實綁紮且於空胴部充填混凝土漿", "鋼板製防護牆之鋼板應施以防銹處理，將鋼板表面清掃，油漆防銹塗料二次後，作修整油漆", "基礎混凝土之配合與強度，除應符合CNS三○九○「預拌混凝土」之規定外，經過二十八日養生後之 抗壓強度應為100 kgf/cm2以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02682', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「防焰性能認證實施要點」之規定敘述，下列何者有誤？', '["防焰物品或其材料之防焰性能加工處理業者，其浸泡之器具，應為長一百公分以上、寬五十公分以上、 高五十公分以上之水槽", "大型布幕無法以浸泡方式進行防焰性能加工處理時，防焰物品或其材料之防焰性能加工處理業者，得 以噴霧塗布之方式，其噴霧器之噴嘴放射壓力不得小於每平方公分五公斤", "材料防焰標示應於防焰性能試驗合格後，依生產或進口數量申請發給，每次不得超過二百張，滿鋪地 毯每次不得超過四百張", "申請物品防焰標示時，須檢附材料防焰標示，每週以申領窗簾類三百張、地毯類二百張為限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02683', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「建築技術規則」有關三層以上之建築物之走廊、樓梯規定，下列敘述何者有誤？', '["直通樓梯於避難層開向屋外之出入口，寬度不得小於一‧二公尺，高度不得小於一‧八公尺", "走廊之地板面有高低時，其坡度不得超過十分之一，並不得設置臺階", "防火構造建築物內各層連接直通樓梯之走廊牆壁及樓地板應具有一小時以上防火時效，並以耐燃一級 材料裝修為限", "集合住宅採取複層式構造者，其自無出入口之樓層居室任一點至直通樓梯之步行距離不得超過五十公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02684', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「建築技術規則」有關特別安全梯規定敘述，下列何者有誤？', '["通達十五層以上或地下三層以下之各樓層，應設置戶外安全梯或特別安全梯", "自室內通陽臺或進入排煙室之出入口，應裝設具有半小時以上防火時效及半小時以上阻熱性之防火門， 自陽臺或排煙室進入樓梯間之出入口應裝設具有半小時以上防火時效之防火門", "樓梯間與排煙室或陽臺之間所開設之窗戶應為固定窗", "建築物在五層以上之樓層供公共集會類組A-1使用者，應設置具有特別安全梯通達之屋頂避難平臺， 屋頂避難平臺面積範圍內不得建造或設置妨礙避難使用之工作物或設施，且通達特別安全梯之最小寬 度不得小於四公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02685', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品試驗方法及判定基準」規定，可燃性固體依物質著火的難易性進行判定，若以閉杯式 閃火點試驗，其試驗方法為將A公克（g）之試驗物品放入試料杯中，蓋上杯蓋。設定溫度，將試料杯保 持於該溫度下B分鐘，然後引燃試驗用火焰，調整火焰直徑至C公厘（mm）大小。啟動開關，將試驗火 焰接觸試料杯D秒後復原，重複試驗找出閃火點，請問前述A，B，C，D為何？', '["1，3，5，3", "5，5，4，2.5", "2，5，4，2.5", "3，5，5，2.5"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02686', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防機關辦理消防安全檢查注意事項」規定，下列何場所消防機關檢查人員應就消防安全設備、檢 修申報、防焰物品、防火管理等項目每年至少清查一次？', '["建築技術規則所定之高層建築物", "製造、儲存或處理公共危險物品達管制量三十倍以上之場所", "液化石油氣製造、儲存及處理場所", "未達管制量之爆竹煙火販賣場所"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02687', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「出口標示燈及避難方向指示燈認可基準」之規定，下列敘述何者正確？', '["內置型引導燈具緊急電源時間應維持60分鐘以上", "內部配線應做好防護措施，與電源接裝之出線，其截面積不得小於0.65 mm2", "燈具配線與電源側電線之連接點溫度上升變化應在30℃以下", "出口標示燈若使用常用電源時，其標示面之平均亮度（cd∕m2）需100以上；若使用緊急電源時，其 標示面之平均亮度需90以上450未滿"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02688', 'fire-eq-tech', 'fire-eq-tech-moex-099-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」有關惰性氣體滅火設備規定，下列敘述何者有誤？', '["確認周圍濕度有無過高，及周圍溫度是否在40℃以下", "將藥劑量之測定結果與重量表、圖面明細表或原廠技術手冊規範核對，其差值應在充填值10%以下", "遲延裝置動作時限應在十五秒以上，且在設計時之設定值範圍內", "語音警報啟動後，須先發出警鈴等警告音響，再播放退避之語音內容，警報系統動作區域正確，且距 揚聲器一公尺處之音量應在九十分貝以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "9095381f2ea9", "answer_pdf_sha1": "6722dd70c930", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02689', 'fire-eq-tech', 'fire-eq-tech-moex-099-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '一般而言，以體積電阻係數區分物體靜電蓄積的難易，其值約為：', '["107Ω．cm", "109Ω．cm", "1011Ω．cm", "1013Ω．cm"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2166e65ae0a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
